import type { Metadata } from 'next';
import { notFound } from 'next/navigation';

import { BackButton } from '@/app/components/back-button';
import { getAllPosts, getCommentsByPostId, getPostById } from '@/app/lib/data';

type BlogPostPageProps = {
  params: Promise<{
    id: string;
  }>;
};

export const revalidate = 300;
export const dynamicParams = true;

export async function generateStaticParams(): Promise<Array<{ id: string }>> {
  const posts = await getAllPosts();

  return posts.slice(0, 10).map((post) => ({
    id: String(post.id),
  }));
}

export async function generateMetadata({ params }: BlogPostPageProps): Promise<Metadata> {
  const { id } = await params;
  const post = await getPostById(id);

  if (!post) {
    return {
      title: 'Post Not Found',
      description: 'The requested post could not be found.',
    };
  }

  const description = post.body?.substring(0, 160) ?? 'Blog post details';

  return {
    title: post.title,
    description,
    openGraph: {
      title: post.title,
      description,
    },
  };
}

export default async function BlogPostPage({ params }: BlogPostPageProps) {
  const { id } = await params;
  const [post, comments] = await Promise.all([getPostById(id), getCommentsByPostId(id)]);

  if (!post) {
    notFound();
  }

  return (
    <article>
      <BackButton />

      <h1>{post.title}</h1>
      <p>{post.body}</p>

      <h2>Comments ({comments.length})</h2>
      <div className="comments">
        {comments.map((comment) => (
          <div key={comment.id} className="comment">
            <h3>{comment.name}</h3>
            <p>{comment.body}</p>
            <small>By: {comment.email}</small>
          </div>
        ))}
      </div>
    </article>
  );
}
