import type { NextRequest } from 'next/server';

import type { Post } from '@/app/lib/types';

type RouteParams = {
  params: Promise<{
    id: string;
  }>;
};

export async function GET(_request: NextRequest, { params }: RouteParams) {
  const { id } = await params;

  const post: Post = {
    id: Number.parseInt(id, 10),
    title: `Post ${id}`,
    content: `This is the content for post ${id}`,
    createdAt: new Date().toISOString(),
  };

  return Response.json(post);
}

export async function PUT(request: NextRequest, { params }: RouteParams) {
  const { id } = await params;
  const body = (await request.json()) as Partial<Pick<Post, 'title' | 'content'>>;
  const { title, content } = body;

  const updatedPost: Post = {
    id: Number.parseInt(id, 10),
    title: title ?? `Post ${id}`,
    content: content ?? `Updated content for post ${id}`,
    updatedAt: new Date().toISOString(),
  };

  return Response.json(updatedPost);
}

export async function DELETE(_request: NextRequest, { params }: RouteParams) {
  const { id } = await params;

  return Response.json({ message: `Post ${id} deleted successfully` });
}
EOF

